def max_prime_distance(nums):
    def is_prime(n):
        if n <= 1:
            return False
        if n == 2:
            return True
        if n % 2 == 0:
            return False
        for i in range(3, int(n**0.5) + 1, 2):
            if n % i == 0:
                return False
        return True

    primes = []
    for idx, num in enumerate(nums):
        if is_prime(num):
            primes.append(idx)

    if len(primes) == 1:
        return 0
    return primes[-1] - primes[0]
